func (s *Server) rolesFromHeaders(h textproto.MIMEHeader) (map[Role]bool, error) {
	raw := strings.TrimSpace(h.Get("X-Roles"))
	if raw == "" {
		return map[Role]bool{RoleUser: true}, nil
	}
	parts := splitCSV(raw)
	roles := make(map[Role]bool, len(parts))
	for _, p := range parts {
		switch Role(strings.ToLower(p)) {
		case RoleUser, RoleMod, RoleAdmin:
			roles[Role(strings.ToLower(p))] = true
		default:
			// ignore unknown roles
		}
	}
	if len(roles) == 0 {
		roles[RoleUser] = true
	}

	if !s.requireSig {
		return roles, nil
	}
	if len(s.secret) == 0 {
		return nil, fmt.Errorf("signature required but secret not configured")
	}

	sig := strings.TrimSpace(h.Get("X-Roles-Sig"))
	if sig == "" {
		return nil, fmt.Errorf("missing signature")
	}
	expect := computeRolesSig(s.secret, raw)
	if !hmac.Equal([]byte(sig), []byte(expect)) {
		return nil, fmt.Errorf("invalid signature")
	}
	return roles, nil
}

func computeRolesSig(secret []byte, rolesHeader string) string {
	m := hmac.New(sha256.New, secret)
	m.Write([]byte("X-Roles:"))
	m.Write([]byte(strings.TrimSpace(rolesHeader)))
	sum := m.Sum(nil)
	return base64.RawURLEncoding.EncodeToString(sum)
}

