func (s *Server) runCommand(actor *Player, cmd AdminCmd) {
	switch cmd.Cmd {
	case "kick":
		if !s.hasAnyRole(actor, RoleMod, RoleAdmin) {
			s.reply(actor, "forbidden")
			return
		}
		if len(cmd.Args) < 1 {
			s.reply(actor, "usage: /kick <player> [reason]")
			return
		}
		target := cmd.Args[0]
		reason := strings.TrimSpace(strings.Join(cmd.Args[1:], " "))
		s.kick(actor, target, reason)
	case "ban":
		if !s.hasAnyRole(actor, RoleAdmin) {
			s.reply(actor, "forbidden")
			return
		}
		if len(cmd.Args) < 1 {
			s.reply(actor, "usage: /ban <player|ip|user:ID> [duration] [reason]")
			return
		}
		target := cmd.Args[0]
		dur, reason := parseDurationAndReason(cmd.Args[1:])
		s.ban(actor, target, dur, reason)
	case "giveitems":
		if !s.hasAnyRole(actor, RoleMod, RoleAdmin) {
			s.reply(actor, "forbidden")
			return
		}
		if len(cmd.Args) < 2 {
			s.reply(actor, "usage: /giveitems <player> <item:qty,item:qty,...>")
			return
		}
		target := cmd.Args[0]
		items := parseItems(strings.Join(cmd.Args[1:], " "))
		if len(items) == 0 {
			s.reply(actor, "no valid items")
			return
		}
		tp := s.findPlayerByNameOrID(target)
		if tp == nil {
			s.reply(actor, "target not found")
			return
		}
		_ = writeFrame(tp.Conn, map[string]any{
			"type": "items",
			"data": map[string]any{"from": actor.Name, "items": items},
		})
		s.reply(actor, "items granted")
	default:
		s.reply(actor, "unknown command")
	}
}

func (s *Server) kick(actor *Player, target, reason string) {
	tp := s.findPlayerByNameOrID(target)
	if tp == nil {
		s.reply(actor, "target not found")
		return
	}
	_ = writeFrame(tp.Conn, map[string]any{
		"type": "system",
		"data": map[string]any{"message": "kicked", "by": actor.Name, "reason": reason},
	})
	_ = tp.Conn.Close()
	s.reply(actor, "kicked")
}

func (s *Server) ban(actor *Player, target string, dur time.Duration, reason string) {
	var banKey string
	if strings.HasPrefix(target, "user:") {
		banKey = target
	} else if net.ParseIP(target) != nil {
		banKey = target
	} else {
		tp := s.findPlayerByNameOrID(target)
		if tp == nil {
			s.reply(actor, "target not found")
			return
		}
		ip := hostOnly(tp.Addr)
		if tp.UserID != "" {
			s.setBan("user:"+tp.UserID, dur)
		}
		s.setBan(ip, dur)
		_ = writeFrame(tp.Conn, map[string]any{
			"type": "system",
			"data": map[string]any{"message": "banned", "by": actor.Name, "reason": reason, "duration": dur.String()},
		})
		_ = tp.Conn.Close()
		s.reply(actor, "banned")
		return
	}

	s.setBan(banKey, dur)
	s.reply(actor, "banned "+banKey)
}

func (s *Server) setBan(key string, dur time.Duration) {
	until := time.Now().Add(dur)
	if dur <= 0 {
		until = time.Now().Add(365 * 24 * time.Hour)
	}
	s.mu.Lock()
	s.bans[key] = until
	s.mu.Unlock()
}

func (s *Server) isBanned(key string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	until, ok := s.bans[key]
	if !ok {
		return false
	}
	if time.Now().After(until) {
		delete(s.bans, key)
		return false
	}
	return true
}

func (s *Server) hasAnyRole(p *Player, roles ...Role) bool {
	for _, r := range roles {
		if p.Roles[r] {
			return true
		}
	}
	return false
}

func (s *Server) reply(p *Player, msg string) {
	_ = writeFrame(p.Conn, map[string]any{
		"type": "system",
		"data": map[string]any{"message": msg},
	})
}

func (s *Server) broadcastChat(from *Player, msg string) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, p := range s.players {
		_ = writeFrame(p.Conn, map[string]any{
			"type": "chat",
			"data": map[string]any{"from": from.Name, "message": msg},
		})
	}
}

func (s *Server) broadcastSystem(msg string, except PlayerID) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for id, p := range s.players {
		if id == except {
			continue
		}
		_ = writeFrame(p.Conn, map[string]any{
			"type": "system",
			"data": map[string]any{"message": msg},
		})
	}
}

func (s *Server) addPlayer(p *Player) {
	s.mu.Lock()
	defer s.mu.Unlock()
	s.players[p.ID] = p
	s.nameToID[strings.ToLower(p.Name)] = p.ID
}

func (s *Server) removePlayer(id PlayerID) {
	s.mu.Lock()
	p := s.players[id]
	if p != nil {
		delete(s.nameToID, strings.ToLower(p.Name))
	}
	delete(s.players, id)
	s.mu.Unlock()
	if p != nil {
		s.broadcastSystem(fmt.Sprintf("%s left", p.Name), id)
	}
}

func (s *Server) findPlayerByNameOrID(q string) *Player {
	q = strings.TrimSpace(q)
	if q == "" {
		return nil
	}
	s.mu.RLock()
	defer s.mu.RUnlock()
	if p, ok := s.players[PlayerID(q)]; ok {
		return p
	}
	if id, ok := s.nameToID[strings.ToLower(q)]; ok {
		return s.players[id]
	}
	return nil
}

func (s *Server) newID() PlayerID {
	n := atomic.AddUint64(&s.nextID, 1)
	return PlayerID(strconv.FormatUint(n, 10))
}

func parseAdminCmd(s string) AdminCmd {
	s = strings.TrimSpace(s)
	if !strings.HasPrefix(s, "/") {
		return AdminCmd{}
	}
	s = strings.TrimPrefix(s, "/")
	if s == "" {
		return AdminCmd{}
	}
	parts := fieldsPreserveQuoted(s)
	if len(parts) == 0 {
		return AdminCmd{}
	}
	cmd := strings.ToLower(parts[0])
	args := []string{}
	if len(parts) > 1 {
		args = parts[1:]
	}
	return AdminCmd{Cmd: cmd, Args: args}
}

func fieldsPreserveQuoted(s string) []string {
	var out []string
	var b strings.Builder
	inQuote := false
	esc := false
	flush := func() {
		if b.Len() > 0 {
			out = append(out, b.String())
			b.Reset()
		}
	}
	for _, r := range s {
		switch {
		case esc:
			b.WriteRune(r)
			esc = false
		case r == '\\':
			esc = true
		case r == '"':
			inQuote = !inQuote
		case !inQuote && (r == ' ' || r == '\t' || r == '\n' || r == '\r'):
			flush()
		default:
			b.WriteRune(r)
		}
	}
	flush()
	return out
}

func parseDurationAndReason(args []string) (time.Duration, string) {
	if len(args) == 0 {
		return 0, ""
	}
	d, err := time.ParseDuration(args[0])
	if err == nil {
		return d, strings.TrimSpace(strings.Join(args[1:], " "))
	}
	return 0, strings.TrimSpace(strings.Join(args, " "))
}

func parseItems(s string) map[string]int {
	s = strings.TrimSpace(s)
	s = strings.Trim(s, "\"")
	parts := splitCSV(s)
	out := map[string]int{}
	for _, p := range parts {
		p = strings.TrimSpace(p)
		if p == "" {
			continue
		}
		kv := strings.SplitN(p, ":", 2)
		if len(kv) != 2 {
			continue
		}
		item := strings.TrimSpace(kv[0])
		if item == "" {
			continue
		}
		qty, err := strconv.Atoi(strings.TrimSpace(kv[1]))
		if err != nil || qty <= 0 {
			continue
		}
		out[item] += qty
	}
	return out
}

func splitCSV(s string) []string {
	var out []string
	for _, p := range strings.Split(s, ",") {
		p = strings.TrimSpace(p)
		if p != "" {
			out = append(out, p)
		}
	}
	return out
}

func sanitizeName(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		return ""
	}
	s = strings.Map(func(r rune) rune {
		if r <= 31 || r == 127 {
			return -1
		}
		return r
	}, s)
	if len(s) > 24 {
		s = s[:24]
	}
	return s
}

func hostOnly(addr string) string {
	h, _, err := net.SplitHostPort(addr)
	if err != nil {
		return addr
	}
	return h
}

func readTextHeaders(br *bufio.Reader, maxBytes int) (textproto.MIMEHeader, error) {
	var buf bytes.Buffer
	for {
		line, err := br.ReadBytes('\n')
		if err != nil {
			return nil, err
		}
		buf.Write(line)
		if buf.Len() > maxBytes {
			return nil, fmt.Errorf("headers too large")
		}
		if bytes.Equal(line, []byte("\n")) || bytes.Equal(line, []byte("\r\n")) {
			break
		}
	}
	tp := textproto.NewReader(bufio.NewReader(bytes.NewReader(buf.Bytes())))
	return tp.ReadMIMEHeader()
}

func readEnvelope(br *bufio.Reader) (Envelope, error) {
	line, err := br.ReadBytes('\n')
	if err != nil {
		return Envelope{}, err
	}
	line = bytes.TrimSpace(line)
	if len(line) == 0 {
		return Envelope{}, fmt.Errorf("empty frame")
	}
	var env Envelope
	if err := json.Unmarshal(line, &env); err != nil {
		return Envelope{}, err
	}
	return env, nil
}

func writeFrame(w io.Writer, v any) error {
	b, err := json.Marshal(v)
	if err != nil {
		return err
	}
	b = append(b, '\n')
	_, err = w.Write(b)
	return err
}

func (s *Server) LoadBans(path string) error {
	f, err := os.Open(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	defer f.Close()
	var m map[string]int64
	if err := json.NewDecoder(f).Decode(&m); err != nil {
		return err
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	for k, v := range m {
		if v == 0 {
			s.bans[k] = time.Now().Add(365 * 24 * time.Hour)
			continue
		}
		s.bans[k] = time.Unix(v, 0)
	}
	return nil
}

func (s *Server) SaveBans(path string) error {
	s.mu.RLock()
	m := make(map[string]int64, len(s.bans))
	for k, v := range s.bans {
		m[k] = v.Unix()
	}
	s.mu.RUnlock()

	tmp := path + ".tmp"
	f, err := os.Create(tmp)
	if err != nil {
		return err
	}
	enc := json.NewEncoder(f)
	enc.SetIndent("", "  ")
	if err := enc.Encode(m); err != nil {
		_ = f.Close()
		_ = os.Remove(tmp)
		return err
	}
	if err := f.Close(); err != nil {
		_ = os.Remove(tmp)
		return err
	}
	return os.Rename(tmp, path)
}